// Validate and extract property data from webhook payload
const body = $input.first().json.body || $input.first().json;

if (!body.id && !body.property_id) {
  throw new Error('Propriedade sem ID — payload inválido');
}

if (!body.price && !body.asking_price) {
  throw new Error('Propriedade sem preço — payload inválido');
}

const property = {
  id: body.id || body.property_id,
  title: (body.title || body.name || 'Propriedade sem título').trim(),
  price: Number(body.price || body.asking_price) || 0,
  zone: (body.zone || body.location || body.area || body.concelho || '').trim(),
  type: (body.type || body.property_type || body.tipologia || '').toLowerCase().trim(),
  yield_potential: Number(body.yield_potential || body.gross_yield || body.yield || 0),
  area_m2: Number(body.area_m2 || body.area || 0),
  opportunity_score: Number(body.opportunity_score || 0),
  bedrooms: Number(body.bedrooms || body.tipologia_quartos || 0),
  description: (body.description || '').substring(0, 500),
  source: body.source || 'manual',
  received_at: new Date().toISOString()
};

return [{ json: property }];

// Investor matching algorithm
const property = $('Code — Validar Propriedade').item.json;
const investors = $input.all().map(i => i.json);

const matchedInvestors = [];

for (const inv of investors) {
  let score = 0;
  const reasons = [];

  // Budget match (30pts): investor max_budget >= property.price * 0.9
  const minAcceptablePrice = property.price * 0.9;
  if (inv.max_budget >= minAcceptablePrice) {
    score += 30;
    reasons.push(`Budget adequado (máx €${(inv.max_budget/1000).toFixed(0)}K vs €${(property.price/1000).toFixed(0)}K)`);
  }

  // Zone match (25pts): property.zone in investor.preferred_zones array
  const preferredZones = Array.isArray(inv.preferred_zones)
    ? inv.preferred_zones
    : (typeof inv.preferred_zones === 'string'
        ? JSON.parse(inv.preferred_zones || '[]')
        : []);
  const propertyZoneLower = (property.zone || '').toLowerCase();
  const zoneMatch = preferredZones.some(z =>
    propertyZoneLower.includes(z.toLowerCase()) || z.toLowerCase().includes(propertyZoneLower)
  );
  if (zoneMatch) {
    score += 25;
    reasons.push(`Zona preferida (${property.zone})`);
  }

  // Type match (20pts): property.type in investor.preferred_types array
  const preferredTypes = Array.isArray(inv.preferred_types)
    ? inv.preferred_types
    : (typeof inv.preferred_types === 'string'
        ? JSON.parse(inv.preferred_types || '[]')
        : []);
  const typeMatch = preferredTypes.some(t =>
    (property.type || '').includes(t.toLowerCase()) || t.toLowerCase().includes(property.type || '')
  );
  if (typeMatch) {
    score += 20;
    reasons.push(`Tipo matching (${property.type})`);
  }

  // Yield match (25pts): property.yield >= investor.min_yield * 0.9
  const minAcceptableYield = (inv.min_yield || 0) * 0.9;
  if (property.yield_potential > 0 && inv.min_yield > 0 && property.yield_potential >= minAcceptableYield) {
    score += 25;
    reasons.push(`Yield de ${property.yield_potential}% >= mínimo ${inv.min_yield}%`);
  } else if (inv.min_yield === 0 || !inv.min_yield) {
    score += 10;
    reasons.push('Sem requisito mínimo de yield');
  }

  // Qualify: total score >= 60
  if (score >= 60) {
    matchedInvestors.push({
      ...inv,
      match_score: score,
      match_reasons: reasons,
      property_id: property.id,
      property_title: property.title,
      property_price: property.price,
      property_zone: property.zone,
      property_type: property.type,
      property_yield: property.yield_potential,
      property_area: property.area_m2
    });
  }
}

matchedInvestors.sort((a, b) => b.match_score - a.match_score);

return matchedInvestors.map(inv => ({ json: inv }));

