// Parse Claude investor alert and merge with investor/property data
const investor = $('Code — Matching Algorithm').item.json;
const rawResponse = $input.item.json;

let claudeText = '';
try {
  claudeText = rawResponse.content?.[0]?.text || rawResponse.text || '{}';
} catch (e) {
  claudeText = '{}';
}

let alert;
try {
  const cleaned = claudeText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  alert = JSON.parse(cleaned);
} catch (e) {
  const firstName = investor.full_name?.split(' ')[0] || 'caro investidor';
  alert = {
    whatsapp_alert: `${firstName}, temos uma oportunidade que corresponde ao seu perfil: ${investor.property_title} — €${(investor.property_price/1000).toFixed(0)}K em ${investor.property_zone}. Match: ${investor.match_score}/100.`,
    email_subject: `Oportunidade de investimento — ${investor.property_zone} — Agency Group`,
    email_intro: `<p>Caro/a ${investor.full_name},</p><p>Identificámos uma oportunidade que corresponde ao seu perfil de investimento com um score de match de ${investor.match_score}/100.</p>`,
    match_summary: investor.match_reasons?.join(', ') || 'Match automático'
  };
}

return [{
  json: {
    ...investor,
    whatsapp_alert: alert.whatsapp_alert,
    email_subject: alert.email_subject,
    email_intro: alert.email_intro,
    match_summary: alert.match_summary
  }
}];

// Aggregate all alerted investors for Slack summary
const allItems = $input.all();
const investorsAlerted = allItems.map(i => ({
  name: i.json.full_name,
  match_score: i.json.match_score,
  contact_id: i.json.contact_id
}));

const property = {
  id: allItems[0]?.json.property_id,
  title: allItems[0]?.json.property_title,
  price: allItems[0]?.json.property_price,
  zone: allItems[0]?.json.property_zone
};

return [{
  json: {
    property_id: property.id,
    property_title: property.title,
    property_price: property.price,
    property_zone: property.zone,
    matches_count: investorsAlerted.length,
    investors_alerted: investorsAlerted,
    executed_at: new Date().toISOString()
  }
}];

